mapper.select:
select apartmentinfo.id, apartmentinfo.name, apartmentinfo.introduction, apartmentinfo.district_id, apartmentinfo.district_name, apartmentinfo.city_id, apartmentinfo.city_name, apartmentinfo.province_id, apartmentinfo.province_name, apartmentinfo.address_detail, apartmentinfo.latitude, apartmentinfo.longitude, apartmentinfo.phone, apartmentinfo.is_release, ifnull(totalcount.cnt, 0) total_room_count, ifnull(totalcount.cnt, 0) - ifnull(checkcount.cnt, 0) free_room_count
from (select id, name, introduction, district_id, district_name, city_id, city_name, province_id, province_name, address_detail, latitude, longitude, phone, is_release from apartment_info
is_deleted = 0
and province_id = #{queryVo.provinceId}
and city_id = #{queryVo.cityId}
and district_id = #{queryVo.districtId}
) apartmentinfo left join (select apartment_id, count(*) cnt from room_info where is_deleted = 0 and is_release = 1 group by apartment_id) totalcount on apartmentinfo.id = totalcount.apartment_id left join (select apartment_id, count(*) cnt from lease_agreement where is_deleted = 0 and status in (2, 5) group by apartment_id) checkcount on apartmentinfo.id = checkcount.apartment_id
